import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.DjxHwWNk.js";const g=JSON.parse('{"title":"УрФУ, Радиофак / РТФ УПИ","description":"Место рождения «Агаты Кристи» и один из студенческих центров свердловского рока.","frontmatter":{"title":"УрФУ, Радиофак / РТФ УПИ","description":"Место рождения «Агаты Кристи» и один из студенческих центров свердловского рока.","outline":"deep"},"headers":[],"relativePath":"places/urfu-rtf.md","filePath":"places/urfu-rtf.md"}'),s={name:"places/urfu-rtf.md"};function o(d,a,n,i,h,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="урфу-радиофак-ртф-упи" tabindex="-1">УрФУ, Радиофак / РТФ УПИ <a class="header-anchor" href="#урфу-радиофак-ртф-упи" aria-label="Permalink to “УрФУ, Радиофак / РТФ УПИ”">​</a></h1><p><strong>Радиотехнический факультет УПИ</strong>, сегодня связанный с Уральским федеральным университетом, — одно из ключевых студенческих мест в истории уральского рока. Именно здесь в середине 1980-х годов возникла группа, которая позже станет одним из главных явлений русского рока, — <strong>«Агата Кристи»</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, ул. Мира, 32</li><li><strong>Период ключевого значения:</strong> середина 1980-х годов</li><li><strong>Главная роль:</strong> место рождения «Агаты Кристи»</li><li><strong>Связанные группы:</strong> «Агата Кристи», «Настя», «Апрельский марш»</li><li><strong>Статус сегодня:</strong> действующий учебный корпус УрФУ</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>РТФ УПИ важен как пространство, где студенческая среда напрямую повлияла на формирование свердловского рока. В отличие от больших концертных площадок, радиофак был не сценой, а местом повседневного творческого общения: здесь учились, репетировали, спорили о музыке, слушали записи, писали тексты и искали новый звук.</p><p>Именно здесь в 1985 году Вадим Самойлов, Александр Козлов и Пётр Май создали группу <strong>«ВИА РТФ УПИ»</strong>. Это название расшифровывалось как «Вокально-инструментальный ансамбль радиофака» и иронично отсылало к советской традиции официальных ВИА. Позднее этот проект вырос в группу <strong>«Агата Кристи»</strong>.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Радиотехнический факультет Уральского политехнического института стал одной из важных точек свердловской студенческой рок-сцены. В середине 1980-х годов здесь сложилась особая творческая атмосфера: студенты не только занимались учёбой, но и активно интересовались музыкой, поэзией, западным роком, постпанком и новой волной.</p><p>В 1985 году Вадим Самойлов, Александр Козлов и Пётр Май создали на радиофаке группу под названием <strong>«ВИА РТФ УПИ»</strong>. Само название звучало как шутка и одновременно как знак времени: музыканты использовали советскую форму «вокально-инструментального ансамбля», но наполняли её совсем другим содержанием.</p><p>В стенах радиофака были записаны первые демо-записи коллектива, в том числе дебютный альбом <strong>«Если...»</strong> 1985 года. Уже в этих ранних материалах проявлялись черты будущего звучания «Агаты Кристи»: мрачная поэтика, индустриальное настроение, влияние постпанка и особая уральская интонация.</p><p>Коридоры, аудитории и студенческая среда РТФ стали для музыкантов пространством эксперимента. Здесь репетировали, обсуждали тексты, спорили о звучании и постепенно формировали тот музыкальный язык, который в 1990-е годы сделает «Агату Кристи» одной из самых узнаваемых групп страны.</p><p>Позднее к группе присоединился младший брат Вадима — Глеб Самойлов. Его появление усилило более жёсткую, драматичную и экспрессивную сторону звучания коллектива. Так студенческий проект радиофака постепенно превратился в одну из главных групп русского рока.</p><p>РТФ УПИ связан не только с «Агатой Кристи». По материалам проекта, здесь также начинали свой путь участники групп <strong>«Настя»</strong>, <strong>«Апрельский марш»</strong> и другие студенты-музыканты, ставшие частью свердловской рок-сцены. Поэтому радиофак можно считать одним из студенческих «инкубаторов» уральского рока.</p><p>В 2024 году на здании РТФ была открыта памятная доска в честь группы <strong>«Агата Кристи»</strong>. Это стало официальным признанием роли факультета в истории уральской рок-культуры.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, ул. Мира, 32.</p><p>Здание находится в университетской части города и может быть включено в маршрут по местам, связанным с «Агатой Кристи» и студенческим Свердловском.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/vadim-samoilov.html">Вадим Самойлов</a></td><td>Основатель и лидер «Агаты Кристи», учился на РТФ</td></tr><tr><td><a href="/Knowledge-Base/people/gleb-samoilov.html">Глеб Самойлов</a></td><td>Позднее присоединился к группе, связан со средой становления «Агаты Кристи»</td></tr><tr><td><a href="/Knowledge-Base/people/alexander-kozlov.html">Александр Козлов</a></td><td>Сооснователь «Агаты Кристи», гитарист</td></tr><tr><td><a href="/Knowledge-Base/people/petr-may.html">Пётр Май</a></td><td>Первый барабанщик группы</td></tr><tr><td>Студенты-музыканты РТФ</td><td>Участники студенческой рок-среды, связанной со свердловской сценой</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/agata-kristi.html">Агата Кристи</a></li><li><a href="/Knowledge-Base/bands/nastya.html">Настя</a></li><li><a href="/Knowledge-Base/bands/aprelsky-marsh.html">Апрельский марш</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня здание продолжает использоваться как учебный корпус УрФУ. В нём располагаются аудитории, лаборатории и образовательные пространства.</p><p>На фасаде установлена памятная доска, посвящённая группе <strong>«Агата Кристи»</strong>. Для поклонников уральского рока это место стало одной из точек памяти, связанных с ранней историей группы и студенческой культурой 1980-х.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Здание является действующим учебным корпусом, поэтому свободный доступ внутрь может быть ограничен. При посещении стоит учитывать режим работы университета и правила прохода.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока РТФ УПИ включается в экскурсионные маршруты как <strong>«родина» группы «Агата Кристи»</strong> и одно из ключевых студенческих мест свердловского рока.</p><p>В материалах проекта также указаны планы лекций и встреч с ветеранами рок-сцены в актовом зале РТФ. Такие события помогают связать университетскую историю, городскую идентичность и музыкальное наследие Екатеринбурга.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Включение РТФ УПИ в экскурсионные маршруты по местам «Агаты Кристи»</td></tr><tr><td>2026 год</td><td>Лекции об истории студенческой рок-сцены</td></tr><tr><td>2026 год</td><td>Встречи с ветеранами уральского рока в актовом зале РТФ</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>РТФ УПИ удобно связывать с другими студенческими и центральными точками уральского рока:</p><ul><li><a href="/Knowledge-Base/places/obschezhitie-11-urfu.html">Общежитие № 11 УрФУ</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li></ul>',33)])])}const m=t(s,[["render",o]]);export{g as __pageData,m as default};
